CREATE TABLE IF NOT EXISTS `{prefix}_forum_cats` ( `id` int(11) NOT NULL AUTO_INCREMENT, `parent_id` int(11) DEFAULT '0', `name` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `description` varchar(500) DEFAULT '', `prefix_id` int(11) DEFAULT '0', `icon` varchar(100) DEFAULT 'fa-folder', `posi` int(11) DEFAULT '0', `topic_count` int(11) DEFAULT '0', `post_count` int(11) DEFAULT '0', `last_topic_id` int(11) DEFAULT '0', `last_post_id` int(11) DEFAULT '0', `permissions` varchar(500) DEFAULT 'all', `allowed_groups` varchar(500) DEFAULT '', `is_private` tinyint(1) DEFAULT '0', `read_groups` varchar(500) DEFAULT '', `write_groups` varchar(500) DEFAULT '', PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `parent_id` (`parent_id`), KEY `is_private` (`is_private`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_topics` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL, `title` varchar(255) NOT NULL, `alt_name` varchar(255) NOT NULL, `description` varchar(500) DEFAULT '', `user_id` int(11) NOT NULL, `views` int(11) DEFAULT '0', `replies` int(11) DEFAULT '0', `is_pinned` tinyint(1) DEFAULT '0', `is_locked` tinyint(1) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `last_bump_date` datetime DEFAULT NULL, `last_post_id` int(11) DEFAULT '0', `last_user_id` int(11) DEFAULT '0', `last_post_date` datetime DEFAULT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `alt_name` (`alt_name`), KEY `cat_id` (`cat_id`), KEY `user_id` (`user_id`), KEY `last_post_date` (`last_post_date`), KEY `is_deleted` (`is_deleted`), KEY `cat_id_deleted_pinned` (`cat_id`,`is_deleted`,`is_pinned`), FULLTEXT KEY `ft_title` (`title`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_posts` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `text` mediumtext NOT NULL, `likes` int(11) DEFAULT '0', `dislikes` int(11) DEFAULT '0', `is_deleted` tinyint(1) DEFAULT '0', `is_approved` tinyint(1) NOT NULL DEFAULT '1', `ip` varchar(45) DEFAULT '', `date` datetime NOT NULL, `updated_at` datetime DEFAULT NULL, PRIMARY KEY (`id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`), KEY `date` (`date`), KEY `topic_id_deleted` (`topic_id`,`is_deleted`), KEY `is_approved` (`is_approved`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_notifs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `from_user` int(11) NOT NULL, `type` varchar(50) NOT NULL, `topic_id` int(11) NOT NULL, `post_id` int(11) DEFAULT '0', `payload` text DEFAULT NULL, `is_read` tinyint(1) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `user_id` (`user_id`), KEY `is_read` (`is_read`), KEY `topic_id` (`topic_id`), KEY `user_id_read_date` (`user_id`,`is_read`,`date`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_ranks` ( `id` int(11) NOT NULL AUTO_INCREMENT, `title` varchar(100) NOT NULL, `points` int(11) NOT NULL DEFAULT '0', `color` varchar(20) DEFAULT '#001f3f', `icon` varchar(100) DEFAULT 'fa-user', `badge_text` varchar(50) DEFAULT '', PRIMARY KEY (`id`), UNIQUE KEY `unique_title` (`title`), KEY `points` (`points`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_subs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`), KEY `topic_id` (`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_likes` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `type` enum('like','dislike') NOT NULL DEFAULT 'like', `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_post` (`user_id`,`post_id`), KEY `post_id` (`post_id`), KEY `post_id_type` (`post_id`,`type`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_readlog` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `last_read_post` int(11) NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), UNIQUE KEY `user_topic` (`user_id`,`topic_id`), KEY `topic_id` (`topic_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_edit_history` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `editor_id` int(11) NOT NULL, `old_text` mediumtext NOT NULL, `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`), KEY `editor_id` (`editor_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_logs` ( `id` int(11) NOT NULL AUTO_INCREMENT, `mod_id` int(11) NOT NULL, `action` varchar(255) NOT NULL, `target_type` varchar(30) DEFAULT 'topic', `topic_id` int(11) DEFAULT '0', `post_id` int(11) DEFAULT '0', `date` datetime NOT NULL, `ip` varchar(45) NOT NULL, PRIMARY KEY (`id`), KEY `mod_id` (`mod_id`), KEY `date` (`date`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_settings` ( `name` varchar(100) NOT NULL, `value` text NOT NULL, PRIMARY KEY (`name`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_banned_words` ( `id` int(11) NOT NULL AUTO_INCREMENT, `word` varchar(255) NOT NULL, `replacement` varchar(255) DEFAULT '***', PRIMARY KEY (`id`), KEY `word` (`word`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_attachments` ( `id` int(11) NOT NULL AUTO_INCREMENT, `post_id` int(11) NOT NULL, `topic_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `filename` varchar(255) NOT NULL, `original_name` varchar(255) NOT NULL, `filesize` int(11) DEFAULT '0', `filetype` varchar(100) DEFAULT '', `mime_type` varchar(100) DEFAULT '', `file_hash` varchar(64) DEFAULT '', `is_image` tinyint(1) DEFAULT '0', `downloads` int(11) DEFAULT '0', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `post_id` (`post_id`), KEY `topic_id` (`topic_id`), KEY `user_id` (`user_id`), KEY `file_hash` (`file_hash`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_flood` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL DEFAULT '0', `ip` varchar(45) NOT NULL DEFAULT '', `action` varchar(50) NOT NULL DEFAULT 'post', `last_action` int(11) NOT NULL DEFAULT '0', `count` int(11) NOT NULL DEFAULT '1', `blocked_until` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `user_action` (`user_id`,`action`), KEY `ip_action` (`ip`,`action`), KEY `blocked_until` (`blocked_until`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_roles` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL DEFAULT '0', `user_id` int(11) NOT NULL DEFAULT '0', `group_id` int(11) NOT NULL DEFAULT '0', `role` enum('admin','moderator','member','banned') NOT NULL DEFAULT 'member', PRIMARY KEY (`id`), UNIQUE KEY `cat_user` (`cat_id`,`user_id`), KEY `cat_id` (`cat_id`), KEY `user_id` (`user_id`), KEY `group_id` (`group_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_conversations` ( `id` int(11) NOT NULL AUTO_INCREMENT, `subject` varchar(255) NOT NULL, `sender_id` int(11) NOT NULL, `recipient_id` int(11) NOT NULL, `created_at` int(11) NOT NULL, `updated_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `sender_id` (`sender_id`), KEY `recipient_id` (`recipient_id`), KEY `updated_at` (`updated_at`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_conversation_users` ( `conversation_id` int(11) NOT NULL, `user_id` int(11) NOT NULL, `last_read_at` int(11) DEFAULT NULL, `is_deleted` tinyint(1) DEFAULT '0', PRIMARY KEY (`conversation_id`,`user_id`), KEY `user_id` (`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_conversations_messages` ( `id` int(11) NOT NULL AUTO_INCREMENT, `conversation_id` int(11) NOT NULL, `sender_id` int(11) NOT NULL, `content` text NOT NULL, `created_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `conversation_id` (`conversation_id`), KEY `sender_id` (`sender_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
-- Forum tablolar─▒ aras─▒ Foreign Key'ler (ayn─▒ DB, cross-prefix sorun de─θil) ALTER TABLE `{prefix}_forum_topics` ADD CONSTRAINT `fk_topics_cat` FOREIGN KEY (`cat_id`) REFERENCES `{prefix}_forum_cats` (`id`) ON DELETE CASCADE;
