ALTER TABLE `{prefix}_forum_notifs` ADD CONSTRAINT `fk_notifs_topic` FOREIGN KEY (`topic_id`) REFERENCES `{prefix}_forum_topics` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_subs` ADD CONSTRAINT `fk_subs_topic` FOREIGN KEY (`topic_id`) REFERENCES `{prefix}_forum_topics` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_likes` ADD CONSTRAINT `fk_likes_post` FOREIGN KEY (`post_id`) REFERENCES `{prefix}_forum_posts` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_readlog` ADD CONSTRAINT `fk_readlog_topic` FOREIGN KEY (`topic_id`) REFERENCES `{prefix}_forum_topics` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_edit_history` ADD CONSTRAINT `fk_edithistory_post` FOREIGN KEY (`post_id`) REFERENCES `{prefix}_forum_posts` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_attachments` ADD CONSTRAINT `fk_attachments_post` FOREIGN KEY (`post_id`) REFERENCES `{prefix}_forum_posts` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_forum_roles` ADD CONSTRAINT `fk_roles_cat` FOREIGN KEY (`cat_id`) REFERENCES `{prefix}_forum_cats` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_conversation_users` ADD CONSTRAINT `fk_convusers_conv` FOREIGN KEY (`conversation_id`) REFERENCES `{prefix}_conversations` (`id`) ON DELETE CASCADE;
ALTER TABLE `{prefix}_conversations_messages` ADD CONSTRAINT `fk_convmsgs_conv` FOREIGN KEY (`conversation_id`) REFERENCES `{prefix}_conversations` (`id`) ON DELETE CASCADE;
