CREATE TABLE IF NOT EXISTS `{prefix}_conversations_messages` ( `id` int(11) NOT NULL AUTO_INCREMENT, `conversation_id` int(11) NOT NULL, `sender_id` int(11) NOT NULL, `content` text NOT NULL, `created_at` int(11) NOT NULL, PRIMARY KEY (`id`), KEY `conversation_id` (`conversation_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
INSERT IGNORE INTO `{prefix}_forum_settings` (`name`, `value`) VALUES ('posts_per_page', '20'), ('topics_per_page', '25'), ('allow_guests_view', '1'), ('min_post_length', '10'), ('max_post_length', '10000'), ('allow_attachments', '1'), ('max_attachment_size', '5242880'), ('allowed_filetypes', 'jpg,jpeg,png,gif,webp,pdf,zip,rar,doc,docx'), ('flood_time', '30'), ('points_new_topic', '10'), ('points_new_reply', '2'), ('points_received_like', '5'), ('approval_threshold', '0'), ('bump_cooldown_hours', '24');
INSERT IGNORE INTO `{prefix}_admin_sections` (`name`, `title`, `descr`, `icon`, `allow_groups`) VALUES ('forum', 'Forum Y├╢netimi', 'DLE Native Forum Ultimate v1.1.2', 'forum.png', '1');
DROP TABLE IF EXISTS `{prefix}_forum_flood`; CREATE TABLE IF NOT EXISTS `{prefix}_forum_flood` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL DEFAULT '0', `ip` varchar(45) NOT NULL DEFAULT '', `action` varchar(50) NOT NULL DEFAULT 'post', `last_action` int(11) NOT NULL DEFAULT '0', `count` int(11) NOT NULL DEFAULT '1', `blocked_until` int(11) NOT NULL DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `user_action` (`user_id`,`action`), KEY `ip_action` (`ip`,`action`), KEY `blocked_until` (`blocked_until`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_visitors` ( `id` int(11) NOT NULL AUTO_INCREMENT, `user_id` int(11) NOT NULL DEFAULT '0', `ip` varchar(45) NOT NULL DEFAULT '', `page` varchar(255) DEFAULT '', `date` datetime NOT NULL, PRIMARY KEY (`id`), KEY `idx_date` (`date`), KEY `idx_date_ip` (`date`,`ip`), KEY `idx_date_user` (`date`,`user_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
ALTER TABLE `{prefix}_forum_topics` ADD COLUMN IF NOT EXISTS `prefix_id` INT(11) DEFAULT '0'; ALTER TABLE `{prefix}_forum_topics` ADD COLUMN IF NOT EXISTS `description` VARCHAR(500) DEFAULT '';
-- v1.1.3 Yeni tablolar (etiket ve ├╢nek sistemi) CREATE TABLE IF NOT EXISTS `{prefix}_forum_prefixes` ( `id` int(11) NOT NULL AUTO_INCREMENT, `cat_id` int(11) NOT NULL DEFAULT '0', `title` varchar(50) NOT NULL, `color` varchar(20) DEFAULT '#3498db', `bg_color` varchar(20) DEFAULT '#ebf5fb', `posi` int(11) DEFAULT '0', PRIMARY KEY (`id`), KEY `cat_id` (`cat_id`), KEY `posi` (`posi`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_tags` ( `id` int(11) NOT NULL AUTO_INCREMENT, `name` varchar(50) NOT NULL, `slug` varchar(50) NOT NULL, `count` int(11) DEFAULT '0', PRIMARY KEY (`id`), UNIQUE KEY `slug` (`slug`), KEY `count` (`count`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE IF NOT EXISTS `{prefix}_forum_topic_tags` ( `topic_id` int(11) NOT NULL, `tag_id` int(11) NOT NULL, PRIMARY KEY (`topic_id`,`tag_id`), KEY `tag_id` (`tag_id`) ) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
