dleplugin.phpinstall:
function forum_seo_write() {

    // έΦΑέΦΑ DLE 19+: DLEUrl sistemi έΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑ
    if (class_exists('DLEUrl')) {

        $rules = [
            'forum_main','forum_cat','forum_topic','forum_user',
            'forum_new_topic','forum_search','forum_notifications',
            'forum_pm','forum_pm_read','forum_ajax'
        ];
        foreach ($rules as $r) {
            DLEUrl::DeleteRule('custom.' . $r);
        }

        DLEUrl::AddRule('forum_main',          '/forum/',                                     'index.php?do=forum');
        DLEUrl::AddRule('forum_new_topic',     '/forum/new-topic/',                           'index.php?do=forum&action=new_topic');
        DLEUrl::AddRule('forum_search',        '/forum/search/',                              'index.php?do=forum&action=search');
        DLEUrl::AddRule('forum_notifications', '/forum/notifications/',                       'index.php?do=forum&action=notifications');
        DLEUrl::AddRule('forum_pm',            '/forum/pm/',                                  'index.php?do=forum&action=pm');
        DLEUrl::AddRule('forum_ajax',          '/forum/ajax/',                                'index.php?do=forum&action=ajax');
        DLEUrl::AddRule('forum_user',          '/forum/user/{user}/',                         'index.php?do=forum&action=user_posts&user={user}');
        DLEUrl::AddRule('forum_pm_read',       '/forum/pm/read/{newsid}/',                    'index.php?do=forum&action=pm&sub=read&id={newsid}');
        DLEUrl::AddRule('forum_topic',         '/forum/{category}/{newsid}-{news_name}.html', 'index.php?do=forum&action=topic&id={newsid}');
        DLEUrl::AddRule('forum_cat',           '/forum/{category}/',                          'index.php?do=forum&action=category&cat={category}');

        if (is_array(DLEUrl::$rules)) {
            $custom_rules = [];
            $other_rules  = [];
            foreach (DLEUrl::$rules as $k => $v) {
                if (strpos($k, 'custom.forum_') === 0) $custom_rules[$k] = $v;
                else $other_rules[$k] = $v;
            }
            DLEUrl::$rules = array_merge($custom_rules, $other_rules);
            DLEUrl::SaveRules(DLEUrl::$rules);
        }

    // έΦΑέΦΑ DLE 18: .htaccess mod_rewrite έΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑέΦΑ
    } else {

        $htaccess_file  = ROOT_DIR . '/.htaccess';
        $marker_start   = '# BEGIN DLE-Forum-SEO';
        $marker_end     = '# END DLE-Forum-SEO';

        $forum_block = $marker_start . '
<IfModule mod_rewrite.c>
RewriteEngine On
RewriteRule ^forum/?$ index.php?do=forum [L,QSA]
RewriteRule ^forum/new-topic/?$ index.php?do=forum&action=new_topic [L,QSA]
RewriteRule ^forum/search/?$ index.php?do=forum&action=search [L,QSA]
RewriteRule ^forum/notifications/?$ index.php?do=forum&action=notifications [L,QSA]
RewriteRule ^forum/pm/?$ index.php?do=forum&action=pm [L,QSA]
RewriteRule ^forum/pm/read/([0-9]+)/?$ index.php?do=forum&action=pm&sub=read&id=$1 [L,QSA]
RewriteRule ^forum/ajax/?$ index.php?do=forum&action=ajax [L,QSA]
RewriteRule ^forum/user/([^/]+)/?$ index.php?do=forum&action=user_posts&user=$1 [L,QSA]
RewriteRule ^forum/([^/]+)/([0-9]+)-([^/]+)\.html$ index.php?do=forum&action=topic&id=$2 [L,QSA]
RewriteRule ^forum/([^/]+)/?$ index.php?do=forum&action=category&cat=$1 [L,QSA]
</IfModule>
' . $marker_end;

        // Mevcut htaccess'i oku (yoksa bo┼θ ba┼θla)
        $current = file_exists($htaccess_file) ? file_get_contents($htaccess_file) : '';

        // Marker'l─▒ blo─θu temizle (varsa έΑΦ upgrade g├╝venli─θi)
        $pattern = '/' . preg_quote($marker_start, '/') . '.*?' . preg_quote($marker_end, '/') . '\s*/s';
        $current = preg_replace($pattern, '', $current);

        // Marker's─▒z eski sat─▒rlar─▒ da temizle (marker silinmi┼θ kenar durum)
        // forum/... RewriteRule sat─▒rlar─▒n─▒ bul ve kald─▒r
        $current = preg_replace('/^RewriteRule\s+\^forum\b.*$/m', '', $current);

        // Bo┼θ sat─▒r birikimini temizle (3+ bo┼θ sat─▒r έΗΤ 1 bo┼θ sat─▒r)
        $current = preg_replace('/\n{3,}/', "\n\n", trim($current));

        // Forum blo─θunu en ├╝ste yaz (DLE'nin kendi kurallar─▒ndan ├╢nce i┼θlenmeli)
        $new_content = $forum_block . "\n\n" . $current;
        file_put_contents($htaccess_file, $new_content);
    }
}

forum_seo_write();

